<script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{askMobileBusinessAssistant,getMobileBusinessAssistantStatus}from'@/api/business';import{useContextStore}from'@/stores';const context=useContextStore(),input=ref(''),answer=ref(''),findings=ref<string[]>([]),actions=ref<string[]>([]),sending=ref(false),enabled=ref(false);onShow(async()=>{try{const s=await getMobileBusinessAssistantStatus();enabled.value=s.enabled&&s.configured}catch{enabled.value=false}});async function send(){if(!input.value.trim()||sending.value)return;sending.value=true;answer.value='';findings.value=[];actions.value=[];try{const r=await askMobileBusinessAssistant({message:input.value,storeId:context.currentStoreId||undefined});answer.value=r.aiAnalysis?.summary||r.localData?.summary||r.error?.message||'暂时没有可展示的分析。';findings.value=r.aiAnalysis?.findings||[];actions.value=(r.aiAnalysis?.actions||[]).map(item=>item.action).filter(Boolean)}catch(e){answer.value=e instanceof Error?e.message:'助手暂时不可用'}finally{sending.value=false}}</script>
<template><view class="page"><text class="title">门店经营助手</text><view class="panel"><textarea v-model="input" placeholder="例如：本月利润下降的主要原因是什么？"/><button :disabled="!enabled" :loading="sending" @click="send">发送</button></view><view v-if="answer" class="answer"><text class="section">分析结论</text><text>{{answer}}</text><template v-if="findings.length"><text class="section">风险发现</text><text v-for="item in findings" :key="item" class="line">{{item}}</text></template><template v-if="actions.length"><text class="section">建议动作</text><text v-for="item in actions" :key="item" class="line">{{item}}</text></template></view><view v-if="!enabled" class="hint">经营助手尚未配置或当前账号无权使用。</view></view></template><style scoped lang="scss">.page{min-height:100vh;padding:24rpx;background:#f2f6f5}.title{font-size:40rpx;font-weight:750}.panel,.answer,.hint{margin-top:18rpx;padding:24rpx;background:#fff;border-radius:16rpx}.panel textarea{box-sizing:border-box;width:100%;height:180rpx;padding:18rpx;background:#f7faf9}.panel button{background:#27655f;color:#fff}.answer{line-height:1.7}.section,.line{display:block}.section{margin-top:18rpx;font-size:28rpx;font-weight:700}.section:first-child{margin-top:0}.line{margin-top:10rpx;padding:14rpx;background:#f7faf9;border-radius:10rpx}.hint{color:#71807d}</style>
